initial.code:
console.log('Elements:', context.panel.elements);

/** 
 * 1. Start Date/Time -> NOW 
  */
const startDtElement = context.panel.elements.find(e => e.id === 'start_date_time');
if (startDtElement) {
  startDtElement.value = new Date().toISOString();
}

/** 
 * 2. End Date/Time -> NOW + 50 Years 
  */
const endDtElement = context.panel.elements.find(e => e.id === 'end_date_time');
if (endDtElement) {
  const futureDate = new Date();
  futureDate.setFullYear(futureDate.getFullYear() + 50);
  // Ensure we are assigning the ISO string version of the future date
  endDtElement.value = futureDate.toISOString();
}

/** 
 * 3. Times, Interval, and Retention 
  */
const startTimeElement = context.panel.elements.find(e => e.id === 'start_time');
if (startTimeElement) {
  //const start = new Date();
  //start.setHours(0, 0, 0, 0); // 00:00:00
  //startTimeElement.value = start.toISOString();
  startTimeElement.value = '00:00:00' 
}

const endTimeElement = context.panel.elements.find(e => e.id === 'end_time');
if (endTimeElement) {
  //const end = new Date();
  //end.setHours(23, 59, 0, 0); // 23:59:00
  //endTimeElement.value = end.toISOString();
  endTimeElement.value = '23:59:59' 
}

const intervalElement = context.panel.elements.find(e => e.id === 'minute_interval');
if (intervalElement) intervalElement.value = '1';

const retentionElement = context.panel.elements.find(e => e.id === 'days_retention');
if (retentionElement) retentionElement.value = '7';

/** 
 * 4. Safe check for the response to prevent "traceId" error 
  */
if (context.panel.response && context.panel.response.data) {
  try {
    const dataQuery = context.utils.toDataQueryResponse(context.panel.response);
    console.log('Processed Data Query:', dataQuery);
  } catch (e) {
    console.error('Error processing data query:', e);
  }
}

return;

resetAction.code:
if (context.panel.response) {
  context.grafana.notifySuccess(['Update', 'Values updated successfully.']);
  context.grafana.refresh();
} else {
  context.grafana.notifyError(['Update', 'An error occurred updating values.']);
}

